 48→func runRigQuickAdd(cmd *cobra.Command, args []string) error {
 49→	targetPath := "."
 50→	if len(args) > 0 {
 51→		targetPath = args[0]
 52→	}
 53→
 54→	absPath, err := filepath.Abs(targetPath)
 55→	if err != nil {
 56→		return fmt.Errorf("resolving path: %w", err)
 57→	}
 58→
 59→	if townRoot, err := workspace.Find(absPath); err == nil && townRoot != "" {
 60→		return fmt.Errorf("already part of a Gas Town workspace: %s", townRoot)
 61→	}
 62→
 63→	gitRoot, err := findGitRoot(absPath)
 64→	if err != nil {
 65→		return fmt.Errorf("not a git repository: %w", err)
 66→	}
 67→
 68→	gitURL, err := findGitRemoteURL(gitRoot)
 69→	if err != nil {
 70→		return fmt.Errorf("no git remote found: %w", err)
 71→	}
 72→
 73→	rigName := sanitizeRigName(filepath.Base(gitRoot))
 74→
 75→	townRoot, err := findOrCreateTown()
 76→	if err != nil {
 77→		return fmt.Errorf("finding Gas Town: %w", err)
 78→	}
 79→
 80→	rigPath := filepath.Join(townRoot, rigName)
 81→	if _, err := os.Stat(rigPath); err == nil {
 82→		return fmt.Errorf("rig %q already exists in %s", rigName, townRoot)
 83→	}
 84→
 85→	originalName := filepath.Base(gitRoot)
 86→	if rigName != originalName && !quickAddQuiet {
 87→		fmt.Printf("Note: Using %q as rig name (sanitized from %q)\n", rigName, originalName)
 88→	}
 89→
 90→	if !quickAddQuiet {
 91→		fmt.Printf("Adding %s to Gas Town...\n", style.Bold.Render(rigName))
 92→		fmt.Printf("  Repository: %s\n", gitURL)
 93→		fmt.Printf("  Town: %s\n", townRoot)
 94→	}
 95→
 96→	addArgs := []string{"rig", "add", rigName, gitURL}
 97→	addCmd := exec.Command("gt", addArgs...)
 98→	addCmd.Dir = townRoot
 99→	addCmd.Stdout = os.Stdout
100→	addCmd.Stderr = os.Stderr
101→	if err := addCmd.Run(); err != nil {
102→		fmt.Printf("\n%s Failed to add rig. You can try manually:\n", style.Warning.Render("⚠"))
103→		fmt.Printf("  cd %s && gt rig add %s %s\n", townRoot, rigName, gitURL)
104→		return fmt.Errorf("gt rig add failed: %w", err)
105→	}
106→
107→	user := quickAddUser
108→	if user == "" {
109→		user = os.Getenv("USER")
110→	}
111→	if user == "" {
112→		user = "default"
113→	}
114→
115→	if !quickAddQuiet {
116→		fmt.Printf("\nCreating crew workspace for %s...\n", user)
117→	}
118→
119→	crewArgs := []string{"crew", "add", user, "--rig", rigName}
120→	crewCmd := exec.Command("gt", crewArgs...)
121→	crewCmd.Dir = filepath.Join(townRoot, rigName)
122→	crewCmd.Stdout = os.Stdout
123→	crewCmd.Stderr = os.Stderr
124→	if err := crewCmd.Run(); err != nil {
125→		fmt.Printf("  %s Could not create crew workspace: %v\n", style.Dim.Render("⚠"), err)
126→		fmt.Printf("  Run manually: cd %s && gt crew add %s --rig %s\n", filepath.Join(townRoot, rigName), user, rigName)
127→	}
128→
129→	crewPath := filepath.Join(townRoot, rigName, "crew", user)
130→	if !quickAddQuiet {
131→		fmt.Printf("\n%s Added to Gas Town!\n", style.Success.Render("✓"))
132→		fmt.Printf("\nYour workspace: %s\n", style.Bold.Render(crewPath))
133→	}
134→
135→	fmt.Printf("GT_CREW_PATH=%s\n", crewPath)
136→
137→	return nil
138→}
