140→func findGitRoot(path string) (string, error) {
141→	cmd := exec.Command("git", "rev-parse", "--show-toplevel")
142→	cmd.Dir = path
143→	out, err := cmd.Output()
144→	if err != nil {
145→		return "", err
146→	}
147→	return strings.TrimSpace(string(out)), nil
148→}
149→
150→func findGitRemoteURL(gitRoot string) (string, error) {
151→	cmd := exec.Command("git", "remote", "get-url", "origin")
152→	cmd.Dir = gitRoot
153→	out, err := cmd.Output()
154→	if err != nil {
155→		return "", err
156→	}
157→	return strings.TrimSpace(string(out)), nil
158→}
