160→func sanitizeRigName(name string) string {
161→	name = strings.ReplaceAll(name, "-", "_")
162→	name = strings.ReplaceAll(name, ".", "_")
163→	name = strings.ReplaceAll(name, " ", "_")
164→	return name
165→}
