380→func confirmUnsafeProceed(force bool) bool {
381→	// If --force and interactive TTY, prompt.
382→	if force && isStdinTerminal() {
383→		fmt.Println()
384→		return promptYesNoUnsafeProceed("Proceed anyway?")
385→	}
386→
387→	// Otherwise block with hint.
388→	if force {
389→		fmt.Printf("\n%s requires an interactive terminal. Use %s to skip all checks (DANGER: will lose work!)\n",
390→			style.Bold.Render("--force"), style.Bold.Render("--nuclear"))
391→	} else {
392→		fmt.Printf("\nUse %s to proceed with confirmation, or %s to skip all checks (DANGER: will lose work!)\n",
393→			style.Bold.Render("--force"), style.Bold.Render("--nuclear"))
394→	}
395→	return false
396→}
