398→// checkUncommittedWork checks polecats in a rig for uncommitted work.
399→// operation is the verb shown in the warning (e.g. "stop", "shutdown", "restart").
400→// Returns true if the caller should proceed, false if it should abort.
401→// When force is true and stdin is a TTY, prompts the user to confirm.
402→// When force is true but stdin is NOT a TTY, blocks (same as no --force).
403→// All user-facing messages are printed internally.
404→func checkUncommittedWork(r *rig.Rig, rigName, operation string, force bool) (proceed bool) {
405→	polecats, err := listPolecatsForWorkCheck(r)
406→	if err != nil {
407→		fmt.Printf("%s Could not check polecats for uncommitted work: %v\n",
408→			style.Warning.Render("⚠"), err)
409→		return confirmUnsafeProceed(force)
410→	}
411→	if len(polecats) == 0 {
412→		return true
413→	}
414→
415→	var problemPolecats []struct {
416→		name   string
417→		status *git.UncommittedWorkStatus
418→	}
419→	var checkErrors []struct {
420→		name string
421→		err  error
422→	}
423→	for _, p := range polecats {
424→		status, err := checkPolecatWorkStatus(p.ClonePath)
425→		if err != nil {
426→			checkErrors = append(checkErrors, struct {
427→				name string
428→				err  error
429→			}{p.Name, err})
430→			continue
431→		}
432→		if status == nil {
433→			checkErrors = append(checkErrors, struct {
434→				name string
435→				err  error
436→			}{p.Name, fmt.Errorf("no status returned")})
437→			continue
438→		}
439→		if !status.Clean() {
440→			problemPolecats = append(problemPolecats, struct {
441→				name   string
442→				status *git.UncommittedWorkStatus
443→			}{p.Name, status})
444→		}
445→	}
446→	if len(problemPolecats) == 0 && len(checkErrors) == 0 {
447→		return true
448→	}
449→
450→	if len(problemPolecats) > 0 {
451→		fmt.Printf("\n%s Cannot %s %s - polecats have uncommitted work:\n",
452→			style.Warning.Render("⚠"), operation, rigName)
453→		for _, pp := range problemPolecats {
454→			fmt.Printf("  %s: %s\n", style.Bold.Render(pp.name), pp.status.String())
455→		}
456→	}
457→	if len(checkErrors) > 0 {
458→		fmt.Printf("\n%s Could not verify uncommitted work for:\n", style.Warning.Render("⚠"))
459→		for _, checkErr := range checkErrors {
460→			fmt.Printf("  %s: %v\n", style.Bold.Render(checkErr.name), checkErr.err)
461→		}
462→	}
463→
464→	return confirmUnsafeProceed(force)
465→}
