472→		return runRigAdopt(cmd, args)
473→	}
474→
475→	// Normal add mode requires git URL
476→	if len(args) < 2 {
477→		return fmt.Errorf("git-url is required (or use --adopt to register an existing directory)")
478→	}
479→	gitURL := args[1]
