509→	mgr := rig.NewManager(townRoot, rigsConfig, g)
510→
511→	fmt.Printf("Creating rig %s...\n", style.Bold.Render(name))
512→	fmt.Printf("  Repository: %s\n", gitURL)
513→	if rigAddLocalRepo != "" {
