521→	}
522→
523→	startTime := time.Now()
524→
525→	// Add the rig
526→	newRig, err := mgr.AddRig(rig.AddRigOptions{
527→		Name:          name,
528→		GitURL:        gitURL,
529→		PushURL:       rigAddPushURL,
530→		BeadsPrefix:   rigAddPrefix,
