532→		DefaultBranch: rigAddBranch,
533→	})
534→	if err != nil {
535→		return fmt.Errorf("adding rig: %w", err)
536→	}
537→
538→	// Save updated rigs config
539→	if err := config.SaveRigsConfig(rigsPath, rigsConfig); err != nil {
540→		return fmt.Errorf("saving rigs config: %w", err)
541→	}
542→
543→	// Add new rig to daemon.json patrol config (witness + refinery rigs arrays)
544→	if err := config.AddRigToDaemonPatrols(townRoot, name); err != nil {
545→		// Non-fatal: daemon will still work, just won't auto-manage this rig
546→		fmt.Printf("  %s Could not update daemon.json patrols: %v\n", style.Warning.Render("!"), err)
547→	}
548→
549→	// Route registration is now handled inside AddRig (before agent bead creation)
550→	// to avoid "no route found" warnings (#1424). Determine beadsWorkDir for rig identity bead.
551→	var beadsWorkDir string
552→	if newRig.Config.Prefix != "" {
