578→	// Sync hooks for the new rig's targets
579→	if err := syncRigHooks(townRoot, name); err != nil {
580→		fmt.Fprintf(os.Stderr, "Warning: failed to sync hooks for new rig: %v\n", err)
581→	}
582→
583→	elapsed := time.Since(startTime)
584→
585→	// Read default branch from rig config
586→	defaultBranch := "main"
