599→	fmt.Printf("  ├── refinery/rig/     (worktree: %s, sees polecat branches)\n", defaultBranch)
600→	fmt.Printf("  ├── crew/             (empty - add crew with 'gt crew add')\n")
601→	fmt.Printf("  ├── witness/\n")
602→	fmt.Printf("  └── polecats/         (.claude/ scaffolded for polecat sessions)\n")
603→
604→	fmt.Printf("\nNext steps:\n")
605→	fmt.Printf("  gt crew add <name> --rig %s   # Create your personal workspace\n", name)
606→	fmt.Printf("  cd %s/crew/<name>              # Start working\n", filepath.Join(townRoot, name))
