611→// GetRigLED returns the LED indicator for a rig based on session and operational state.
612→// Used by both rig list and statusline for consistent indicators:
613→//   - 🟢 = both witness and refinery running (fully active)
614→//   - 🟡 = one session running (partially active)
615→//   - ⚫ = nothing running (stopped)
616→//   - 🅿️ = parked (intentionally paused)
617→//   - 🛑 = docked (global shutdown)
618→func GetRigLED(hasWitness, hasRefinery bool, opState string) string {
619→	if hasWitness && hasRefinery {
620→		return "🟢"
621→	}
622→	if hasWitness || hasRefinery {
623→		return "🟡"
624→	}
625→	switch opState {
626→	case "PARKED":
627→		return "🅿️"
628→	case "DOCKED":
629→		return "🛑"
630→	default:
631→		return "⚫"
632→	}
633→}
