635→// rigStatePriority returns a sort priority for a rig's state.
636→// Lower values sort first: active > partial > stopped > parked > docked.
637→func rigStatePriority(hasWitness, hasRefinery bool, opState string) int {
638→	if hasWitness && hasRefinery {
639→		return 0
640→	}
641→	if hasWitness || hasRefinery {
642→		return 1
643→	}
644→	switch opState {
645→	case "PARKED":
646→		return 3
647→	case "DOCKED":
648→		return 4
649→	default:
650→		return 2
651→	}
652→}
