1368→			if cfgErr := mayorGit.ConfigurePushURL("origin", pushURL); cfgErr != nil {
1369→				return nil, fmt.Errorf("configuring mayor push URL: %w", cfgErr)
1370→			}
1371→		}
1372→	} else if pushURLAuthoritative {
