1481→// seedPatrolMolecules creates patrol molecule prototypes in the rig's beads database.
1482→// These molecules define the work loops for Deacon, Witness, and Refinery roles.
1483→func (m *Manager) seedPatrolMolecules(rigPath string) error {
1484→	// Use bd command to seed molecules (more reliable than internal API)
1485→	cmd := exec.Command("bd", "mol", "seed", "--patrol")
1486→	cmd.Dir = rigPath
1487→	if err := cmd.Run(); err != nil {
1488→		// Fallback: bd mol seed might not support --patrol yet
1489→		// Try creating them individually via bd create
1490→		return m.seedPatrolMoleculesManually(rigPath)
1491→	}
1492→	return nil
1493→}
