1541→// createPluginDirectories creates plugin directories at town and rig levels.
1542→// - ~/gt/plugins/ (town-level, shared across all rigs)
1543→// - <rig>/plugins/ (rig-level, rig-specific plugins)
1544→func (m *Manager) createPluginDirectories(rigPath string) error {
1545→	// Town-level plugins directory
1546→	townPluginsDir := filepath.Join(m.townRoot, "plugins")
1547→	if err := os.MkdirAll(townPluginsDir, 0755); err != nil {
1548→		return fmt.Errorf("creating town plugins directory: %w", err)
1549→	}
1550→
1551→	// Create a README in town plugins if it doesn't exist
1552→	townReadme := filepath.Join(townPluginsDir, "README.md")
1553→	if _, err := os.Stat(townReadme); os.IsNotExist(err) {
1554→		content := `# Gas Town Plugins
1555→
1556→This directory contains town-level plugins that run during Deacon patrol cycles.
1557→
1558→## Plugin Structure
1559→
1560→Each plugin is a directory containing:
1561→- plugin.md - Plugin definition with TOML frontmatter
1562→
1563→## Gate Types
1564→
1565→- cooldown: Time since last run (e.g., 24h)
1566→- cron: Schedule-based (e.g., "0 9 * * *")
1567→- condition: Metric threshold
1568→- event: Trigger-based (startup, heartbeat)
1569→
1570→See docs/deacon-plugins.md for full documentation.
1571→`
1572→		if writeErr := os.WriteFile(townReadme, []byte(content), 0644); writeErr != nil {
1573→			// Non-fatal
1574→			return nil
1575→		}
1576→	}
1577→
1578→	// Rig-level plugins directory
1579→	rigPluginsDir := filepath.Join(rigPath, "plugins")
1580→	if err := os.MkdirAll(rigPluginsDir, 0755); err != nil {
1581→		return fmt.Errorf("creating rig plugins directory: %w", err)
1582→	}
1583→
1584→	// Add plugins/, .repo.git/, and .land-worktree/ to rig .gitignore
1585→	gitignorePath := filepath.Join(rigPath, ".gitignore")
1586→	if err := m.ensureGitignoreEntry(gitignorePath, "plugins/"); err != nil {
1587→		return err
1588→	}
1589→	if err := m.ensureGitignoreEntry(gitignorePath, ".repo.git/"); err != nil {
1590→		return err
1591→	}
1592→	return m.ensureGitignoreEntry(gitignorePath, ".land-worktree/")
1593→}
