136→// GetRig returns a specific rig by name.
137→func (m *Manager) GetRig(name string) (*Rig, error) {
138→	entry, ok := m.config.Rigs[name]
139→	if !ok {
140→		return nil, ErrRigNotFound
141→	}
142→
143→	return m.loadRig(name, entry)
